import { Component, h, Prop } from '@stencil/core';

export type StatusLabelVariant = 'success' | 'warning' | 'informational' | 'error';

@Component({
  tag: 'wdpr-card-status-label',
  styles: `:host { width: 100%; }`,
  shadow: true,
})
export class WdprCardStatusLabel {
  @Prop() label: string;
  @Prop() variant: StatusLabelVariant = 'informational';

  get variantClasses() {
    return {
      success: 'bg-surface-status-success-alt-2',
      warning: 'bg-surface-status-warning-alt-2',
      informational: 'bg-surface-status-informational-alt-2',
      error: 'bg-surface-status-critical',
    };
  };

  get textColor() {
    return {
      success: 'text-text-status-success',
      warning: 'text-text-status-warning',
      informational: 'text-text-body',
      error: 'text-text-inverse',
    };
  };

  get iconName() {
    switch (this.variant) {
      case 'success':
        return 'checkmark';
      case 'warning':
        return 'alert';
      case 'error':
        return 'alert-notification-1';
      case 'informational':
        return 'info';
    }
  };

  render() {
    const variantBg = this.variantClasses[this.variant];
    const textColor = this.textColor[this.variant];
    const showIcon = true;
    const containerClasses = `box-border flex h-dimension-450 items-center py-112 px-200 w-full ${variantBg} ${textColor}`;

    return (
      <div class={containerClasses}>
        {
          showIcon &&
          <div class={textColor}>
            <wdpr-icon-library icon={this.iconName} size="xxsmall"></wdpr-icon-library>
          </div>
        }

        <div class="font-body-alt component-small w-full pl-050 pt-025">
          {this.label}
        </div>
      </div>
    );
  }
}
